/** REST API ラッパーのエラー基底クラス */
export class ApiBaseError extends Error {
    constructor() {
        super(...arguments);
        this.name = 'ApiBaseError';
    }
}
/** REST API のリクエスト関連のエラー */
export class ApiDomError extends ApiBaseError {
    constructor(message, name = 'ApiDomError', options) {
        super(message, options);
        this.name = name;
    }
}
/** REST API の HTTP ステータスコード検証エラー */
export class ApiHttpStatusError extends ApiBaseError {
    constructor(message, status, options) {
        super(message, options);
        this.status = status;
        this.name = 'ApiHttpStatusError';
    }
}
/** REST API の認証関連エラー */
export class ApiAuthError extends ApiHttpStatusError {
    constructor(message, options) {
        super(message, 401, options);
        this.name = 'ApiAuthError';
    }
}
export class ApiServiceError extends ApiHttpStatusError {
    constructor(message, options) {
        super(message, 503, options);
        this.name = 'ApiServiceError';
    }
}
export class InvalidRequestError extends ApiHttpStatusError {
    constructor(message, options) {
        super(message, 400, options);
        this.name = 'BadRequestError';
    }
}
export class ApiNotFoundError extends ApiHttpStatusError {
    constructor(message, options) {
        super(message, 404, options);
        this.name = 'ApiNotFoundError';
    }
}
/** REST API レスポンスのペイロード関連のエラー */
export class ApiResponseError extends ApiBaseError {
    constructor() {
        super(...arguments);
        this.name = 'ApiResponseError';
    }
}
/** REST API レスポンスのストリーム処理の際のエラー */
export class ApiStreamError extends ApiResponseError {
    constructor(message, error, options) {
        super(message, options);
        this.error = error;
        this.name = 'ApiStreamError';
    }
}
/** REST API のレスポンスペイロード responseHeader 内 status の検証エラー */
export class ApiCommonStatusError extends ApiResponseError {
    constructor(message, responseHeader, options) {
        super(message, options);
        this.responseHeader = responseHeader;
        this.name = 'ApiCommonStatusError';
    }
}
export class ResponseTooLargeError extends Error {
    constructor() {
        super(...arguments);
        this.name = 'ResponseTooLarge';
    }
}
export class VoxelTypeError extends Error {
    constructor(message, options) {
        super(message, options);
        this.name = 'VoxelTypeError';
    }
}
